mapper.select:
SELECT
ORDER BY adj_seq desc
,ai.adj_seq AS adjSeq ,ai.atvy_srial_no AS atvySrialNo ,CASE WHEN ai.biz_cont_no = 0 THEN ai.svc_cont_no ELSE ai.biz_cont_no END AS tgtContNo ,CASE WHEN ai.svc_cont_no > 0 THEN (SELECT svc_no FROM svc_no_hst WHERE ai.svc_cont_no = svc_cont_no AND efct_st_dt <= ai.cret_dt AND efct_fns_dt > ai.cret_dt) ELSE NULL END AS svcNo ,ai.adj_tgt_bill_tgt_ym AS useYm ,TO_CHAR(ai.cret_dt, 'YYYYMMDD') AS adjCretDate ,CASE WHEN ai.adj_aply_dt IS NOT NULL THEN TO_CHAR(ai.adj_aply_dt, 'YYYYMMDD') END AS adjAplyDate ,ai.adj_amt AS adjAmt ,ai.vat_adj_amt AS vatAdjAmt ,ai.adj_lvl_cd AS adjLvlCd ,CASE WHEN ai.chage_seq > 0 THEN (SELECT bill_lctg_cd || bill_mctg_cd FROM chage_info WHERE chage_seq = ai.chage_seq) WHEN ai.bill_cnfm_seq > 0 THEN (SELECT bill_item_cd FROM bill_cnfm_info WHERE bill_cnfm_seq = ai.bill_cnfm_seq) END AS billItemCd ,ai.rsn_cd AS rsnCd ,CASE WHEN (SELECT count(atvy_srial_no) from adj_info where bill_acc_no = ai.bill_acc_no and adj_seq = ai.adj_seq AND atvy_srial_no != 1)>0 THEN 'Y' ELSE 'N' END AS adjCanYn ,ai.cretr_id AS adjTrtId ,ai.cret_dt AS adjTrtDt FROM adj_info ai WHERE ai.bill_acc_no = #{tgtNo} AND ai.atvy_srial_no = 1
AND ai.biz_cont_no = #{subTgtNo}
AND ai.svc_cont_no = #{subTgtNo}
AND ai.cret_dt >= #{fromDt} ORDER BY ai.adj_seq DESC, ai.atvy_srial_no

SELECT
ORDER BY adj_seq desc
,ai.cret_dt AS cretDt ,ai.amd_dt AS amdDt ,ai.adj_aply_dt AS adjAplyDt ,ai.bill_acc_no AS billAccNo ,ai.biz_cont_no AS bizContNo ,ai.svc_cont_no AS svcContNo ,CASE WHEN ai.svc_cont_no > 0 THEN (SELECT svc_no FROM svc_no_hst WHERE ai.svc_cont_no = svc_cont_no AND efct_st_dt <= ai.cret_dt AND efct_fns_dt > ai.cret_dt) ELSE NULL END AS svcNo ,ai.adj_tgt_bill_tgt_ym AS adjTgtBillTgtYm ,ci.cust_nm AS custNm ,CASE WHEN ai.adj_cd = 'ADJ' THEN '조정' WHEN ai.adj_cd = 'ADJR' THEN '조정취소' END AS adjTypeNm ,CASE WHEN ai.chage_seq > 0 THEN (SELECT bill_lctg_cd || bill_mctg_cd FROM chage_info WHERE chage_seq = ai.chage_seq) WHEN ai.bill_cnfm_seq > 0 THEN (SELECT bill_item_cd FROM bill_cnfm_info WHERE bill_cnfm_seq = ai.bill_cnfm_seq) END AS billItemCd ,ai.rsn_cd AS rsnCd ,ai.adj_amt AS adjAmt ,ai.vat_adj_amt AS vatAdjAmt ,ai.balc_impct_cd AS blncImpctCd ,ai.cretr_id AS adjTrtId ,ai.cmpn_cd AS cmpnCd ,ai.biz_cd AS bizCd ,ai.adj_seq AS adjSeq ,ai.adj_lvl_cd AS adjLvlCd FROM adj_info ai , bill_acc_info bai , cust_info ci WHERE ai.cret_dt >= #{fromDt} AND ai.cret_dt <= #{toDt} AND ai.bill_acc_no = bai.bill_acc_no AND bai.bill_acc_cust_no = ci.cust_no
AND ai.bill_acc_no = #{tgtNo}
AND rsn_cd = #{divCd}
bai.cmpn_cd = #{cmpnBizInfo.cmpnCd} AND bai.biz_cd = #{cmpnBizInfo.bizCd}
ORDER BY ai.cret_dt DESC


        SELECT 
			CASE WHEN ai.chage_seq > 0 THEN (SELECT bill_lctg_cd || bill_mctg_cd FROM chage_info WHERE chage_seq = ai.chage_seq)
				 WHEN ai.bill_cnfm_seq > 0 THEN (SELECT bill_item_cd FROM bill_cnfm_info WHERE bill_cnfm_seq = ai.bill_cnfm_seq)
			END AS billItemCd
			,ai.adj_amt		AS adjAmt
        FROM adj_info ai
       WHERE ai.bill_acc_no			= #{billAccNo}
         AND ai.adj_tgt_bill_tgt_ym	= #{adjTgtBillTgtYm} 
         AND ai.rsn_cd					= #{rsnCd} 



		 AND ai.svc_cont_no			= #{svcContNo}




		 AND ai.biz_cont_no			= #{bizContNo}
